#include "useraccount.hpp"

void UserAccount::AddToPortfolio(const std::string &asset, int amount) {
  portfolio_[asset] += amount;
}

bool UserAccount::CheckPortfolio(const std::string &asset,
                                 int amount) const {
  if (portfolio_.count(asset) > 0 && portfolio_.at(asset) >= amount) {
    return true;
  }
  return false;
}

void UserAccount::RemoveFromPortfolio(const std::string &asset,
                                       int amount) {
  portfolio_[asset] -= amount;
}

void UserAccount::PrintPortfolio(
    const std::map<std::string, int> &exchange_portfolio, std::ostream &os) const {
  for (const auto &p : portfolio_) {
    if (p.second > 0 && exchange_portfolio.count(p.first) > 0) {
      os << p.second << " " << p.first << " ($" << p.second * exchange_portfolio.at(p.first) / 100000.0 << ")";
      if (p.first == "USD") {
        os << " (Free: " << p.second - exchange_portfolio.at(p.first) << ")";
      }
      os << ", ";
    }
  }
  os << std::endl;
}
